var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"으으… 힘들다.","JPN":"うう……結構しんどいですね。","ENG":"Whew... I'm tired.","TWN":"呃……好累。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"정말로 날 업고 여기까지 올라올 줄은 몰랐는데…","JPN":"まさか本当に私をおんぶして上るなんて……","ENG":"I didn't think you really would carry me all the way here...","TWN":"沒想到你真的把我背到了這裡……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"괜찮아?","JPN":"大丈夫か？","ENG":"You all right?","TWN":"你還好嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"아하핫… 걱정 마세요. 조금 쉬면 금방 괜찮아질 거예요.","JPN":"あはは……大丈夫です。少し休めばすぐ回復するので。","ENG":"Ah hah hah... Don't worry. I'll be fine after a small break.","TWN":"啊哈哈……不用擔心。稍微休息一下，就沒事了。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"그런데, 다른 사람들이 안 보이네요. 먼저 조사하러 갔으려나?","JPN":"ところで、他のみなさんがいなくなりましたね。　先に探索を進めているんでしょうか？","ENG":"But I don't see the others. Maybe they went off to investigate on their own?","TWN":"但是，我沒看到其他人。也許他們先一步去調查了？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이런 낭떠러지에서 떨어졌으니… 내가 죽었다 생각하고 승강기로 먼저 탈출했을지도 모르지.","JPN":"こんな深いところに落ちたのを見たら、もう私は死んだと思って先に昇降機に乗って脱出したかもな。","ENG":"I fell off a cliff... They could've taken the elevator back up, thinking I was dead.","TWN":"我從那麼高的地方掉下去……他們可能以為我已經死了，就先搭升降機逃走了吧。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"우와, 너무해! 정말로 그런 거라면 완전 최악이네요!","JPN":"ええっ！　もし本当にそうだとしたら、あまりにも酷いです！","ENG":"No way! If they did, they're the worst!","TWN":"哇，太過分了吧！如果真是這樣，那真是太惡劣了！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"읏…?!","JPN":"うっ……！？","ENG":"Ngh...?!","TWN":"咕嚕嚕……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"하긴 그 높은 곳을 나까지 업고 올라왔는데, 배가 고프지 않은 것도 이상하지.","JPN":"私をおぶって高いところまで運んだんだから、当然腹も空くだろう。","ENG":"Well, you did carry me a long way. No wonder you're hungry.","TWN":"也對，你爬了那麼高的地方，不餓才怪呢。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그 친구들이 물자는 남겨두고 가서 다행이네.","JPN":"幸い、物資は置いていったみたいだ。","ENG":"I'm glad they left their supplies behind.","TWN":"幸好那兩人沒帶走補給。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"즉석비프스튜인데, 괜찮아?","JPN":"レトルトのビーフシチューでもいいか？","ENG":"It's instant beef stew. You okay with that?","TWN":"這是即食燉牛肉，可以嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"아, 감사합니다.","JPN":"あっ、ありがとうございます。","ENG":"Oh, thanks.","TWN":"啊，謝謝。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"으음…","JPN":"うむ……","ENG":"Mmm...","TWN":"嗯……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"왜 그래? 그 정도론 부족해?","JPN":"どうした？　量が足りないのか？","ENG":"What's wrong? Not enough?","TWN":"怎麼了？這些不夠嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"아, 아뇨. 그런 건 아닌데요.","JPN":"い、いいえ。そういうわけじゃ。","ENG":"No, that's not it.","TWN":"不、不是。不是那樣。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"저… 괜찮다면 전 저쪽에서 혼자 먹어도 될까요?","JPN":"あの……失礼じゃなかったら、あっちで一人で食べてもいいですか？","ENG":"Um... If it's fine with you, can I eat alone over there?","TWN":"那個……如果可以的話，我可以一個人去那邊吃飯嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"상관은 없지만… 왜?","JPN":"かまわないが、どうした？","ENG":"Sure... But why?","TWN":"當然……但為什麼？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"다른 사람에게 밥 먹는 모습을 보이는 거, 별로 익숙하지 않아서요. 헤헤…","JPN":"ただ、他の人にご飯を食べるとこを見られるの、あまり慣れていなくて。へへっ……","ENG":"I'm not used to other people seeing me eat. Hehe...","TWN":"我不太習慣在別人面前吃東西。哈哈……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"subtitle","speaker":null,"text":{"KOREA":"G동. 격납고 및 의료 시설.","JPN":"G棟。格納庫兼医療施設。","ENG":"G Wing. Hangar and medical facilities.","TWN":"G棟。機庫和醫療設施。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"어이, 거기 뭐 좀 찾았어?","JPN":"おい、何かあったか？","ENG":"Hey, you find anything there?","TWN":"喂，你在那裡有什麼發現嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"그래, 우리 예상이 맞았군.","JPN":"ああ、やっぱりあったぞ。","ENG":"Yeah, just as we thought.","TWN":"嗯，我們猜的沒錯。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"현실부상용 다이빙 벨을 확보했다. 다행히 고장 나진 않았어.","JPN":"現実浮上用ダイビングベルを確保した。幸い、問題なく動いてくれそうだ。","ENG":"I found a Normalside Diving Bell. It's still in good shape.","TWN":"我發現了用於躍出的潛水鐘。幸好還沒被破壞。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"좋아! 당장 그걸 타고 여길 뜨자고!","JPN":"よしっ！　早速それに乗ってここを出ようぜ！","ENG":"Nice! Let's get on that thing and get out of here!","TWN":"很好！我們現在就出發吧！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"아니. 다이빙 벨의 드라이브를 가동하려면 이터니움이 꽤나 필요해.","JPN":"いや。ダイビングベルのドライブシステムを稼働させるには、相当量のエタニウムが必要になる。","ENG":"No. We'll need a lot of Eternium to get the Diving Bell's drive up and running.","TWN":"不行。啟動潛水鐘需要大量的永恆之金。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"지금 상태는 연료통이 빈 차나 다름없어.","JPN":"このままでは燃料切れの車と同じだ。","ENG":"Right now, it's out of juice.","TWN":"現在的它就好比一輛耗盡燃油的汽車。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"미치겠네. 채굴지도 아닌 곳에서 무슨 수로 이터니움을 구해? 침식체라도 잡으란 거야?","JPN":"くそっ、まじかよ。採掘地でもないのにどうやってエタニウムを手に入れるんだ？　侵食体でも倒せというのか？","ENG":"Goddammit. This place isn't a mine. How are we gonna find Eternium? Take down some C.O.s?","TWN":"真是見鬼。這裡又不是礦場，我們從哪裡找這麼多永恆之金？靠殺侵蝕體嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"가까운 곳에 메디컬 센터가 있을 거다.","JPN":"近くにメディカルセンターがあるはずだ。","ENG":"There must be a medical center nearby.","TWN":"這附近有一個醫療中心。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"거기에 의료용 이터니움이 남아있길 바라야지.","JPN":"そこに行って、医療用エタニウムが手に入るのを祈るしかないな。","ENG":"Let's hope there's some medical Eternium left there.","TWN":"希望那裡還剩下一些醫用永恆之金吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"응…? 방금 천장에서 뭔 소리가…","JPN":"うん……？　おい、今天井から何か物音がしなかったか？","ENG":"Hm...? I just heard something from the ceiling...","TWN":"嗯……？我剛剛聽到天花板上有什麼聲音……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"무슨 소리죠?","JPN":"これって、なんの音ですか？","ENG":"What was that?","TWN":"這個是什麼？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"선발대가 가지고 있던 침식파 탐지기야. 주변 침식환경이 급변하고 있다는 신호지.","JPN":"先発隊が携帯していた侵食波探知機だ。周辺の侵食環境が急変しているという警告音を出している。","ENG":"It's the Corruption ray detector the advance party had. It's telling us that the surrounding Corruption environment is undergoing rapid change.","TWN":"這是先遣隊攜帶的侵蝕波探測器。它會在周圍侵蝕環境迅速變化時發出訊號。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"침식체가 있는 걸까요?","JPN":"侵食体がいるのでしょうか？","ENG":"Could there be C.O.s around?","TWN":"也就是說明，這附近有侵蝕體嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그래, 그것도 굉장히 가까이에 있어.","JPN":"ああ、しかもすぐ近くにいる。","ENG":"Yeah. And very close.","TWN":"嗯，它離這裡非常近了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"온다.","JPN":"来る。","ENG":"They're coming.","TWN":"來了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"맡겨주세요. 뭔가 튀어나오면 바로 잘라버릴게요.","JPN":"お任せください。何が出てきても斬り落としますから。","ENG":"Leave it to me. If anything pops out, I'll cut it down.","TWN":"交給我吧。有什麼東西冒出來，我就立刻鋸斷它。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"잠깐… 방금 총소리가 들렸어.","JPN":"待て……今銃声が聞こえた。","ENG":"Wait... I just heard gunshots.","TWN":"等等……我剛剛聽到了槍響。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"옆쪽 통로야.","JPN":"すぐ隣の通路からだ。","ENG":"It's from the corridor next to us.","TWN":"是旁邊的通道。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"제길. 어디까지 도망쳐야 하는 건데? 이러다 탄약이 먼저 바닥나겠어!","JPN":"くっそ、どこまで逃げればいいんだ？　弾薬が持たないぞ！","ENG":"Dammit. How long do we have to run for? We're gonna run out of bullets first!","TWN":"可惡。我們還要逃去哪？再這樣下去，我就要沒子彈了！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L18_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"어이, 저쪽에 대장이 보인다.","JPN":"おい、あれって隊長じゃないか？","ENG":"Hey, I see Captain over there.","TWN":"喂，我看到隊長在那邊了！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"뭐? 정말 살아있잖아?","JPN":"え？　本当に生きていたな？","ENG":"What? She's really alive?","TWN":"什麼？她真的還活著？"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"아까 지알로 녀석과 똑같은 패턴 아냐? 갔더니 우릴 공격하는 건 아니겠지?","JPN":"まさか、さっきのジャッロと同じで、近づいたら攻撃してくるとか？","ENG":"What if she's turned like Giallo did? What if she attacks us?","TWN":"她不會和賈洛一樣了吧？我們要是去了那裡，不會被她攻擊？"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"어차피 살려면 합류하는 수밖에 없어.","JPN":"合流しなければどのみち死ぬのは一緒だ。","ENG":"We have to regroup if we want to live anyway.","TWN":"想活下去的話，就只能和她們會合了。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"커크, 쿠바!","JPN":"カーク、クバ！","ENG":"Kirk, Cuba!","TWN":"寇克，庫巴！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"바리케이드 넘는 대로 몸을 숙여!","JPN":"バリケードを飛び越えたら、すぐにしゃがめ！","ENG":"Duck as soon as you cross the barricade!","TWN":"過路障的時候，記得俯身！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"으윽… 제길! 따라 잡힌다!","JPN":"くっ……ちくしょ！　追いつかれる！","ENG":"Ack... Crud! We're not gonna make it!","TWN":"啊……該死！它追過來了！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"…엎드려!","JPN":"……伏せろ！","ENG":"...Get down!","TWN":"……趴下！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"어서 오세요, 여러분.","JPN":"いらっしゃいませ、みなさん。","ENG":"Welcome, everyone.","TWN":"歡迎回來~"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"통로에 있던 침식체들이… 전부 반으로 갈라졌어. 이게 카운터 능력이란 건가?","JPN":"通路にうじゃうじゃといた侵食体が……一匹残らず真っ二つになったぞ。カウンターの能力ってこんなにすごいのか？","ENG":"All the C.O.s... got sliced in half. Is this what a Counter can do?","TWN":"通道內的侵蝕體……全都被切成兩半了。這就是制裁者的能力嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"더 온다. 막을 준비해!","JPN":"もっと来るぞ。構えろ！","ENG":"More are coming. Get ready to block them!","TWN":"更多的侵蝕體過來了。準備攔住它們！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"},"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"여기서 엄호해주세요. 제가 앞에서 막을게요!","JPN":"ここで援護していてください！　私が前面に立って食い止めます！","ENG":"Cover me. I'll get them from the front!","TWN":"你們在這裡掩護隊長。我去前面擋住它們！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SERIOUS"},"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"위험해. 어둠 속이라 피아구분이 잘 안 된다고.","JPN":"やめとけ、こんな暗闇の中じゃお前を避けて撃つことはできないぞ。","ENG":"It's too dangerous. It's too dark to tell friendlies apart.","TWN":"太危險了！光線太弱，會容易誤傷到你！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SERIOUS"},"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"괜찮아요! 실수로 저 쏘셔도 돼요!","JPN":"大丈夫ですから、遠慮なく撃ってください！","ENG":"That's fine! I don't mind if you shoot me!","TWN":"沒事的！射中我也沒關係！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_PRIDE"},"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"나중에 아프다며 원망하지 말라고.","JPN":"痛いとか文句言っても知らないからな！","ENG":"Don't go complaining later.","TWN":"那好！射到你可別怪我！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_PRIDE"},"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"}]`);export{e as default};